+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+};
+
+const tocStartMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEndMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^(?: {0,3})(#{1,6})(?:[ \	]+(.*?)\\s*|\\s*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const eol = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const startIndex = lines.findIndex((line) => tocStartMarker.test(line));
+
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(startIndex + 1).findIndex((line) => tocEndMarker.test(line));
+    const endIndex = endOffset === -1 ? -1 : startIndex + endOffset + 1;
+    const headings = this.getHeadings(lines, startIndex, endIndex, options);
+    const tocLines = this.buildTocLines(headings, options);
+
+    const markerEnd = endIndex === -1 ? startIndex : endIndex;
+    let afterIndex = markerEnd + 1;
+    while (afterIndex < lines.length && lines[afterIndex].trim() === '') {
+      afterIndex++;
+    }
+
+    const replacement = [lines[startIndex], ''];
+    if (options.title.trim() !== '') {
+      replacement.push(options.title, '');
+    }
+    replacement.push(...tocLines, '', '<!-- /toc -->', '');
+
+    const result = [...lines.slice(0, startIndex), ...replacement, ...lines.slice(afterIndex)];
+    if (afterIndex === lines.length) {
+      result.push('');
+    }
+    return result.join(eol);
+  }
+
+  private getHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    let inYaml = lines[0]?.trim() === '---';
+    let codeFence: string = null;
+    let inMath = false;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+
+      if (inYaml) {
+        if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) {
+          inYaml = false;
+        }
+        continue;
+      }
+
+      const fence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+      if (codeFence) {
+        if (fence && fence[1][0] === codeFence[0] && fence[1].length >= codeFence.length) {
+          codeFence = null;
+        }
+        continue;
+      }
+      if (fence) {
+        codeFence = fence[1];
+        continue;
+      }
+
+      if (/^\\s*\\$\\$\\s*$/.test(line)) {
+        inMath = !inMath;
+        continue;
+      }
+      if (inMath || (index > tocStart && tocEnd !== -1 && index < tocEnd)) {
+        continue;
+      }
+
+      const match = line.match(atxHeading);
+      if (!match) {
+        continue;
+      }
+
+      const level = match[1].length;
+      const headingText = match[2] ?? '';
+      const displayText = this.displayText(headingText, options.stripFormattingInToc);
+      const comparableText = this.displayText(headingText, true);
+      if (level >= options.minLevel && level <= options.maxLevel && !this.isExcluded(comparableText, options.excludeHeadings)) {
+        headings.push({level, text: displayText});
+      }
+    }
+
+    return headings;
+  }
+
+  private buildTocLines(headings: Heading[], options: AutoTocOptions): string[] {
+    const anchors = new Map<string, number>();
+    return headings.map((heading, index) => {
+      const baseAnchor = this.anchorFor(heading.text, options.useExplicitIds);
+      const duplicateCount = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, duplicateCount + 1);
+      const anchor = duplicateCount === 0 ? baseAnchor : `${baseAnchor}-${duplicateCount}`;
+      const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
+      return `${indentation}${marker} [${this.removeExplicitId(heading.text)}](#${anchor})`;
+    });
+  }
+
+  private anchorFor(text: string, useExplicitIds: boolean): string {
+    const explicitId = text.match(/\\s*\\{#([^}]+)\\}\\s*$/);
+    const source = useExplicitIds && explicitId ? explicitId[1] : this.removeExplicitId(text);
+    return this.stripFormatting(source)
+      .replace(/\\s+#+\\s*$/, '')
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+  }
+
+  private displayText(text: string, stripFormatting: boolean): string {
+    let display = this.removeExplicitId(text).replace(/\\s+#+\\s*$/, '');
+    display = display
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1')
+      .trim();
+    return stripFormatting ? this.stripFormatting(display).trim() : display;
+  }
+
+  private stripFormatting(text: string): string {
+    return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1')
+      .replace(/(`+)(.*?)\\1/g, '$2')
+      .replace(/(\\*\\*|__|~~|\\*|_)(.*?)\\1/g, '$2');
+  }
+
+  private removeExplicitId(text: string): string {
+    return text.replace(/\\s*\\{#[^}]+\\}\\s*$/, '').trim();
+  }
+
+  private isExcluded(heading: string, exclusions: string[]): boolean {
+    return exclusions.some((exclusion) => {
+      if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+        try {
+          return new RegExp(exclusion.slice(1, -1), 'i').test(heading);
+        } catch {
+          return heading.toLowerCase() === exclusion.toLowerCase();
+        }
+      }
+      return heading.toLowerCase() === exclusion.toLowerCase();
+    });
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder<AutoTocOptions, ListStyle>({
+        OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle',
+        records: [{value: 'bullet', description: 'Use a bulleted list.'}, {value: 'number', description: 'Use a numbered list.'}],
+      }),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder<AutoTocOptions, OrderedListStyle>({
+        OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle',
+        records: [{value: 'always-one', description: 'Use 1. for every item.'}, {value: 'increment', description: 'Increment item numbers across the TOC.'}],
+      }),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
